def load_json(path: Path):
    return json.loads(path.read_text(encoding="utf-8"))


def choice_map(values):
    return {label: value for label, value in zip(["А", "Б", "В", "Г"], values)}


def shuffle_options(correct, distractors, rnd):
    values = [correct] + distractors[:3]
    rnd.shuffle(values)
    options = choice_map(values)
    for label, value in options.items():
        if value == correct:
            return options, label
    raise RuntimeError("missing correct option")


def word_count(text):
    return len(text.split())


def extend_text(text, paragraphs, target_words=700, fallback_paragraph=None):
    out = text
    for paragraph in paragraphs:
        if word_count(out) >= target_words:
            break
        out += "\n\n" + paragraph
    while fallback_paragraph and word_count(out) < target_words:
        out += "\n\n" + fallback_paragraph
    return out


