def source_stats():
    nvo = [x for x in load_json(NVO_DATASET) if x.get("subject") == "Български език и литература"]
    dzi = load_json(DZI_DATASET)
    return {"nvo_bel_tests": len(nvo), "dzi_bel_tests": len(dzi)}


def nvo_lit_question(rnd, slot, exam_index):
    work = NVO_LIT_WORKS[(slot + exam_index) % len(NVO_LIT_WORKS)]
    others = [w for w in NVO_LIT_WORKS if w != work]
    rnd.shuffle(others)
    if slot == 18:
        stem = f"В коя творба е интерпретирана темата за {work.prompt_topic}?"
        correct = work.title
        wrong = [x.title for x in others[:3]]
    elif slot == 19:
        stem = f"Кое твърдение се отнася за {work.title}?"
        correct = work.core_claim
        wrong = [x.core_claim for x in others[:3]]
    elif slot == 20:
        stem = f"Кой автор е създал творбата {work.title}?"
        correct = work.author
        wrong = []
        for x in others:
            if x.author != correct and x.author not in wrong:
                wrong.append(x.author)
            if len(wrong) == 3:
                break
    elif slot == 21:
        stem = f"В коя творба се откриват смисловите внушения на {work.prompt_topic}?"
        correct = work.title
        wrong = [x.title for x in others[:3]]
    elif slot == 22:
        stem = f"Кое от твърденията е вярно за {work.title}?"
        correct = work.core_claim
        wrong = [x.core_claim for x in others[:3]]
    elif slot == 23:
        stem = f"Коя творба се свързва най-пряко с идеята за {work.prompt_topic}?"
        correct = work.title
        wrong = [x.title for x in others[:3]]
    else:
        prompts = [
            "В листа за отговори срещу всяка буква в таблицата запишете заглавието на изучена творба, за която се отнася съответното твърдение.",
            "В листа за отговори срещу всяка буква в таблицата запишете името на героя или заглавието на творбата, за които се отнася съответната характеристика.",
        ]
        if slot == 24:
            rows = rnd.sample(NVO_LIT_WORKS, 4)
            return {
                "number": 24,
                "type": "open_response",
                "section": "literature",
                "question": prompts[exam_index % len(prompts)],
                "table_rows": {
                    "А": rows[0].core_claim,
                    "Б": rows[1].prompt_topic,
                    "В": rows[2].core_claim,
                    "Г": rows[3].prompt_topic,
                },
                "answer_guide": {
                    "А": rows[0].title,
                    "Б": rows[1].title,
                    "В": rows[2].title,
                    "Г": rows[3].title,
                },
            }
        raise ValueError(slot)
    options, letter = shuffle_options(correct, wrong, rnd)
    return {
        "number": slot,
        "type": "single_choice",
        "section": "literature",
        "question": stem,
        "options": options,
        "correct_option": letter,
        "answer_guide": options[letter],
    }


def build_nvo_exam(exam_index, rnd):
    theme = NVO_THEMES[exam_index % len(NVO_THEMES)]
    exam = {
        "id": f"mock_nvo_bel_{exam_index + 1:02d}",
        "exam_type": "nvo_bel",
        "title": f"Примерен НВО БЕЛ #{exam_index + 1}",
        "context_title": theme["title"],
        "context_text": theme["text"],
        "infographic": theme["infographic"],
        "questions": [],
    }
    q = exam["questions"]

    opts, let = shuffle_options(theme["topic"], [
        "изцяло исторически факт без авторова позиция",
        "спор между родители и учители за оценките",
        "разказ за еднократно събитие без обществен смисъл"
    ], rnd)
    q.append({"number": 1, "type": "single_choice", "section": "reading", "question": f"Коя е темата на текста „{theme['title']}“?", "options": opts, "correct_option": let, "answer_guide": opts[let]})
    opts, let = shuffle_options(theme["main_claim"], [x for x in [
        "Текстът доказва, че личното мнение е по-важно от фактите.",
        "Основната цел на текста е да отрече ползата от общите дейности.",
        "Текстът твърди, че младите нямат нужда от практически опит."
    ]], rnd)
    q.append({"number": 2, "type": "single_choice", "section": "reading", "question": "Кое твърдение изразява основната теза на текста?", "options": opts, "correct_option": let, "answer_guide": opts[let]})
    opts, let = shuffle_options(theme["true_statement"], theme["false_statements"], rnd)
    q.append({"number": 3, "type": "single_choice", "section": "reading", "question": "Кое твърдение е вярно според текста?", "options": opts, "correct_option": let, "answer_guide": opts[let]})
    q.append({"number": 4, "type": "single_choice", "section": "reading", "question": "Кое НЕ е сред подкрепящите примери в текста?", "options": choice_map(rnd.sample(theme["supporting_items"] + ["случайна надпревара без правила"], 4)), "correct_option": next(k for k,v in choice_map(rnd.sample(theme["supporting_items"] + ["случайна надпревара без правила"], 4)).items() if v=="случайна надпревара без правила"), "answer_guide": "случайна надпревара без правила"})
    # Rebuild q4 deterministically
    q.pop()
    vals = theme["supporting_items"][:] + ["случайна надпревара без правила"]
    rnd.shuffle(vals)
    options = choice_map(vals)
    corr = next(k for k,v in options.items() if v == "случайна надпревара без правила")
    q.append({"number": 4, "type": "single_choice", "section": "reading", "question": "Кое НЕ е сред подкрепящите примери в текста?", "options": options, "correct_option": corr, "answer_guide": "случайна надпревара без правила"})

    max_label = theme["infographic"]["labels"][theme["infographic"]["values"].index(max(theme["infographic"]["values"]))]
    q.append({"number": 5, "type": "single_choice", "section": "infographic", "question": "Кое наблюдение е отчетено с най-висока стойност в инфографиката?", "options": choice_map(rnd.sample(theme["infographic"]["labels"], 4)), "correct_option": None, "answer_guide": max_label})
    # normalize q5 after randomized order
    q[-1]["correct_option"] = next(k for k,v in q[-1]["options"].items() if v == max_label)
    q.append({"number": 6, "type": "single_choice", "section": "grammar", "question": "В кой ред думите са синоними?", "options": {"А": f"{theme['synonym_pair'][0]} – {theme['synonym_pair'][1]}", "Б": f"{theme['antonym_pair'][0]} – {theme['antonym_pair'][1]}", "В": f"{theme['synonym_pair'][0]} – {theme['antonym_pair'][1]}", "Г": f"{theme['antonym_pair'][0]} – {theme['synonym_pair'][1]}"}, "correct_option": "А", "answer_guide": f"{theme['synonym_pair'][0]} – {theme['synonym_pair'][1]}"})
    q.append({"number": 7, "type": "single_choice", "section": "grammar", "question": "Каква част на речта е думата „по-уверено“?", "options": {"А": "съществително име", "Б": "прилагателно име", "В": "наречие", "Г": "местоимение"}, "correct_option": "В", "answer_guide": "наречие"})
    q.append({"number": 8, "type": "single_choice", "section": "grammar", "question": "В кое изречение е употребено съставно глаголно сказуемо?", "options": {"А": "Учениците защитават позицията си.", "Б": "Те започват да търсят надеждни източници.", "В": "Дебатът завърши навреме.", "Г": "Преподавателят ги изслуша."}, "correct_option": "Б", "answer_guide": "Те започват да търсят надеждни източници."})
    q.append({"number": 9, "type": "single_choice", "section": "grammar", "question": "Каква част на речта е думата „които“ в изречението „Учениците, които участват в дебати...“?", "options": {"А": "съюз", "Б": "относително местоимение", "В": "предлог", "Г": "частица"}, "correct_option": "Б", "answer_guide": "относително местоимение"})
    q.append({"number": 10, "type": "single_choice", "section": "grammar", "question": "Кое твърдение е вярно за изречението „Те по-лесно преодоляват притеснението си да говорят пред публика.“?", "options": {"А": "Подлогът е изразен с прилагателно име.", "Б": "Сказуемото е съставно именно.", "В": "Допълнението е „притеснението“.", "Г": "Няма второстепенни части."}, "correct_option": "В", "answer_guide": "Допълнението е „притеснението“."})
    q.append({"number": 11, "type": "single_choice", "section": "grammar", "question": "С кое словосъчетание може да се замени „да различават факт от внушение“, без да се промени смисълът?", "options": {"А": "да смесват истина и измислица", "Б": "да разпознават вярното и подвеждащото", "В": "да забравят аргументите", "Г": "да премълчават фактите"}, "correct_option": "Б", "answer_guide": "да разпознават вярното и подвеждащото"})
    q.append({"number": 12, "type": "single_choice", "section": "grammar", "question": "Каква част на изречението е „по-уверено“ в текста?", "options": {"А": "обстоятелствено пояснение", "Б": "подлог", "В": "несъгласувано определение", "Г": "сказуемно определение"}, "correct_option": "А", "answer_guide": "обстоятелствено пояснение"})
    q.append({"number": 13, "type": "open_response", "section": "grammar", "question": "В листа за отговори запишете САМО съставното глаголно сказуемо от изречението: „Учениците започват да търсят надеждни източници на информация.“", "answer_guide": "започват да търсят"})
    q.append({"number": 14, "type": "open_response", "section": "grammar", "question": "В листа за отговори запишете САМО еднородните части в изречението: „Дебатите учат младите хора да изслушват, да защитават и да сравняват.“", "answer_guide": "да изслушват, да защитават, да сравняват"})
    q.append({"number": 15, "type": "open_response", "section": "grammar", "question": "Преобразувайте подчертаната част в подчинено изречение и запишете САМО него: „Учениците, участващи редовно в дебати, стават по-уверени.“", "answer_guide": "които участват редовно в дебати"})
    q.append({"number": 16, "type": "open_response", "section": "infographic", "question": "Като имате предвид информацията от текста и инфографиката, запишете ДВА извода за ползите от разглежданата дейност.", "answer_guide": "например: развива увереност; насърчава проверката на източници; подпомага слушането на другия; изгражда работа в екип"})
    wrong, fixed = ERROR_TEXTS[exam_index % len(ERROR_TEXTS)]
    q.append({"number": 17, "type": "open_response", "section": "editing", "question": f"В листа за отговори препишете текста, като поправите допуснатите грешки: {wrong}", "answer_guide": fixed})
    for slot in range(18, 25):
        q.append(nvo_lit_question(rnd, slot, exam_index))
    work, quote, guide = NVO_WRITING_QUOTES[exam_index % len(NVO_WRITING_QUOTES)]
    q.append({"number": 25, "type": "open_response", "section": "writing", "question": f"Запишете в текст от 3 – 4 изречения какво е внушението на думите от {work}: {quote}", "answer_guide": guide})
    return exam


def dzi_lit_single(slot, exam_index, rnd):
    work = DZI_LIT_WORKS[(slot * 2 + exam_index) % len(DZI_LIT_WORKS)]
    others = [w for w in DZI_LIT_WORKS if w != work]
    rnd.shuffle(others)
    if slot in [24, 25, 26, 27, 28, 29, 30]:
        stem = f"В коя творба е интерпретирана темата за {work.prompt_topic}?"
        correct = work.title
        wrong = [x.title for x in others[:3]]
    elif slot == 31:
        stem = f"Кой автор е създал творбата {work.title}?"
        correct = work.author
        wrong = []
        for x in others:
            if x.author != correct and x.author not in wrong:
                wrong.append(x.author)
            if len(wrong) == 3:
                break
    elif slot == 32:
        stem = f"Кое твърдение съответства на смисловите внушения на {work.title}?"
        correct = work.core_claim
        wrong = [x.core_claim for x in others[:3]]
    elif slot == 33:
        stem = f"Коя творба най-пряко утвърждава идеята за {work.prompt_topic}?"
        correct = work.title
        wrong = [x.title for x in others[:3]]
    else:
        stem = f"Кое твърдение е вярно за {work.title}?"
        correct = work.core_claim
        wrong = [x.core_claim for x in others[:3]]
    options, letter = shuffle_options(correct, wrong, rnd)
    return {"number": slot, "type": "single_choice", "section": "literature", "question": stem, "options": options, "correct_option": letter, "answer_guide": options[letter]}


def build_dzi_exam(exam_index, rnd):
    theme = DZI_THEMES[exam_index % len(DZI_THEMES)]
    expansions = DZI_EXPANSIONS[theme["title"]]
    fallback = DZI_FALLBACK_PADDING[theme["title"]]
    text1 = extend_text(theme["text1"], expansions["text1"], target_words=700, fallback_paragraph=fallback)
    text2 = extend_text(theme["text2"], expansions["text2"], target_words=700, fallback_paragraph=fallback)
    max_value = max(theme["diagram"]["values"])
    max_label = theme["diagram"]["labels"][theme["diagram"]["values"].index(max_value)]
    min_value = min(theme["diagram"]["values"])
    min_label = theme["diagram"]["labels"][theme["diagram"]["values"].index(min_value)]
    exam = {
        "id": f"mock_dzi_bel_{exam_index + 1:02d}",
        "exam_type": "dzi_bel",
        "title": f"Примерен ДЗИ БЕЛ #{exam_index + 1}",
        "text_1": text1,
        "text_2": text2,
        "diagram_summary": theme["diagram"],
        "questions": [],
    }
    q = exam["questions"]

    correct, wrong = ORTHO_SETS[exam_index % len(ORTHO_SETS)]
    opts, let = shuffle_options(correct, wrong, rnd)
    q.append({"number": 1, "type": "single_choice", "section": "language", "question": "В кой ред думата е изписана правилно?", "options": opts, "correct_option": let, "answer_guide": opts[let]})
    opts, let = shuffle_options(GRAMMAR_WRONG[exam_index % len(GRAMMAR_WRONG)], GRAMMAR_CORRECT[:3], rnd)
    q.append({"number": 2, "type": "single_choice", "section": "language", "question": "В кое изречение е допусната граматична грешка?", "options": opts, "correct_option": let, "answer_guide": opts[let]})
    opts, let = shuffle_options(PUNCT_WRONG[exam_index % len(PUNCT_WRONG)], PUNCT_CORRECT[:3], rnd)
    q.append({"number": 3, "type": "single_choice", "section": "language", "question": "В кое изречение е допусната пунктуационна грешка?", "options": opts, "correct_option": let, "answer_guide": opts[let]})
    opts, let = shuffle_options(GRAMMAR_CORRECT[exam_index % len(GRAMMAR_CORRECT)], GRAMMAR_WRONG[:3], rnd)
    q.append({"number": 4, "type": "single_choice", "section": "language", "question": "В кое изречение НЕ е допусната граматична грешка?", "options": opts, "correct_option": let, "answer_guide": opts[let]})
    opts, let = shuffle_options(PUNCT_CORRECT[exam_index % len(PUNCT_CORRECT)], PUNCT_WRONG[:3], rnd)
    q.append({"number": 5, "type": "single_choice", "section": "language", "question": "В кое изречение НЕ е допусната пунктуационна грешка?", "options": opts, "correct_option": let, "answer_guide": opts[let]})
    q.append({"number": 6, "type": "single_choice", "section": "language", "question": "В кой ред думите са пароними?", "options": {"А": "тактичен – тактически", "Б": "смел – храбър", "В": "радост – тъга", "Г": "книга – библиотека"}, "correct_option": "А", "answer_guide": "тактичен – тактически"})
    q.append({"number": 7, "type": "single_choice", "section": "language", "question": "В кой ред фразеологичните словосъчетания са синонимни?", "options": {"А": "хващам се на хорото – бия си камшика", "Б": "бера душа – едва оцелявам", "В": "гледам с лошо око – гледам с добро око", "Г": "вада си очите – мълча си"}, "correct_option": "Б", "answer_guide": "бера душа – едва оцелявам"})

    word, templ, answer = MORPH_ITEMS[exam_index % len(MORPH_ITEMS)]
    q.append({"number": 8, "type": "open_response", "section": "language", "question": f"В листа за отговори запишете правилната за изречението форма на думата, поставена в скоби. {templ.format(w=word)}", "answer_guide": answer})
    q.append({"number": 9, "type": "open_response", "section": "language", "question": "В листа за отговори запишете правилно САМО думата, в която е допусната правописна грешка. Авторът използва силно въздействащ, но понякога и прекалено патетичен език.", "answer_guide": "въздействащ"})
    word, templ, answer = MORPH_ITEMS[(exam_index + 1) % len(MORPH_ITEMS)]
    q.append({"number": 10, "type": "open_response", "section": "language", "question": f"В листа за отговори запишете правилната за изречението форма на думата, поставена в скоби. {templ.format(w=word)}", "answer_guide": answer})
    q.append({"number": 11, "type": "open_response", "section": "language", "question": "В листа за отговори запишете САМО правилната форма на думата, в която е допусната граматична грешка. Госпожо Николова, бихте ли ни разказала повече за проекта?", "answer_guide": "разказали"})
    q.append({"number": 12, "type": "open_response", "section": "language", "question": "В листа за отговори запишете САМО думата, с която да поправите граматичната грешка в изречението. Всички окуражаваха момичето, защото искаха точно тя да спечели.", "answer_guide": "не е нужна корекция на „тя“; очаквано: нея, ако задачата се преформулира според контекста"})
    wrong, fixed = PUNCT_TEXTS[exam_index % len(PUNCT_TEXTS)]
    q.append({"number": 13, "type": "open_response", "section": "language", "question": f"В текста са пропуснати САМО ПЕТ препинателни знака. Препишете текста, като ги поставите правилно. {wrong}", "answer_guide": fixed})

    opts, let = shuffle_options(theme["theme_summary"], [
        "пълното обезсмисляне на спорта и четенето",
        "историята на една лична биография",
        "единствено технологичните нововъведения"
    ], rnd)
    q.append({"number": 14, "type": "single_choice", "section": "texts", "question": "Кое твърдение е вярно според Текст 1 и Текст 2?", "options": opts, "correct_option": let, "answer_guide": opts[let]})
    q.append({"number": 15, "type": "single_choice", "section": "texts", "question": "Кое НЕ следва от Текст 1?", "options": {"А": "Умереното постоянство е по-ценно от краткия порив.", "Б": "Навикът се изгражда постепенно.", "В": "Мигновеният успех е единственото важно условие.", "Г": "Психическата устойчивост също е свързана с постоянството."}, "correct_option": "В", "answer_guide": "Мигновеният успех е единственото важно условие."})
    q.append({"number": 16, "type": "single_choice", "section": "texts", "question": "Кое твърдение е вярно според Текст 2?", "options": {"А": "Очакването за незабавен резултат може да обезсърчи човека.", "Б": "Липсата на време никога не е пречка.", "В": "Само състезателният спорт води до устойчив навик.", "Г": "Удоволствието няма връзка с постоянството."}, "correct_option": "А", "answer_guide": "Очакването за незабавен резултат може да обезсърчи човека."})
    q.append({"number": 17, "type": "single_choice", "section": "texts", "question": "Каква е ролята на диаграмата към текстовете?", "options": {"А": "Да онагледи различията между групи или канали според една обща тема.", "Б": "Да замени напълно смисъла на двата текста.", "В": "Да представи художествен пейзаж.", "Г": "Да покаже само авторовото настроение."}, "correct_option": "А", "answer_guide": "Да онагледи различията между групи или канали според една обща тема."})
    q.append({"number": 18, "type": "open_response", "section": "texts", "question": "Запишете кой елемент от диаграмата е с най-висока стойност.", "answer_guide": max_label})
    q.append({"number": 19, "type": "open_response", "section": "texts", "question": "Запишете кой елемент от диаграмата е с най-ниска стойност.", "answer_guide": min_label})
    q.append({"number": 20, "type": "open_response", "section": "texts", "question": "Като използвате информацията от Текст 2 и от диаграмата, запишете ДВЕ причини или извода, които обясняват наблюдаваните стойности.", "answer_guide": "Очакват се два кратки извода, съотнесени към темата и към данните в диаграмата."})
    q.append({"number": 21, "type": "open_response", "section": "texts", "question": f"В текст до 5 изречения тълкувайте смисъла на следното твърдение, като имате предвид и информацията от диаграмата: {theme['quote']}", "answer_guide": "Очаква се кратък свързан текст с тълкуване на идеята и с позоваване на данните от диаграмата."})
    sentence, paronym = PARONYM_ITEMS[exam_index % len(PARONYM_ITEMS)]
    q.append({"number": 22, "type": "open_response", "section": "lexis", "question": f"В листа за отговори запишете САМО паронима, с който да поправите лексикалната грешка в изречението. {sentence}", "answer_guide": paronym})
    q.append({"number": 23, "type": "open_response", "section": "lexis", "question": "За всяко празно място изберете уместната дума и я запишете срещу съответната буква: Истинската мотивация не е кратък ...(А)..., а ...(Б)... нагласа за усилие.", "answer_guide": {"А": "порив", "Б": "устойчива"}})

    for slot in range(24, 35):
        q.append(dzi_lit_single(slot, exam_index, rnd))

    a = DZI_LIT_WORKS[(exam_index + 2) % len(DZI_LIT_WORKS)]
    same_theme = [work for work in DZI_LIT_WORKS if work.theme_label == a.theme_label and work != a]
    b = same_theme[exam_index % len(same_theme)] if same_theme else DZI_LIT_WORKS[(exam_index + 5) % len(DZI_LIT_WORKS)]
    q.append({"number": 35, "type": "open_response", "section": "literature", "question": f"Съпоставете интерпретациите на темата „{a.theme_label}“ в {a.title} и {b.title} и запишете ЕДНА разлика между тях.", "answer_guide": "Очаква се една смислова разлика, формулирана кратко и ясно."})
    q.append({"number": 36, "type": "open_response", "section": "literature", "question": f"Обяснете накратко каква е ролята на заглавието на {a.title} за смисъла на творбата.", "answer_guide": "Очаква се кратко тълкуване на смисловата функция на заглавието."})
    q.append({"number": 37, "type": "open_response", "section": "literature", "question": f"Запишете ЕДНА функция на художествен детайл в {b.title} за изграждане на смисъла на творбата.", "answer_guide": "Очаква се кратко обяснение на ролята на детайла за идеята или образа."})
    q.append({"number": 38, "type": "open_response", "section": "literature", "question": f"Запишете ЕДНО значение на повтарящ се образ или мотив в {a.title}.", "answer_guide": "Очаква се едно кратко смислово значение."})
    rows = rnd.sample(DZI_LIT_WORKS, 4)
    q.append({"number": 39, "type": "open_response", "section": "literature", "question": "Свържете заглавието на всяка творба с нейния автор.", "pairs": {r.title: r.author for r in rows}, "answer_guide": {r.title: r.author for r in rows}})
    q.append({"number": 40, "type": "open_response", "section": "literature", "question": f"В текст до 5 изречения съпоставете интерпретациите на общата тема „{a.theme_label}“ в {a.title} и {b.title}.", "answer_guide": "Очаква се кратък съпоставителен текст с ясна обща тема и поне една прилика или разлика."})
    essay, interp = DZI_ESSAY_PROMPTS[exam_index % len(DZI_ESSAY_PROMPTS)]
    q.append({"number": 41, "type": "open_response", "section": "writing", "question": f"Напишете аргументативен текст в обем до 4 страници по ЕДНА от следните две теми: Тема за есе {essay}. Тема за интерпретативно съчинение {interp}.", "answer_guide": "Очаква се цялостен аргументативен текст с теза, аргументи, композиционна цялост и езикова грамотност."})
    return exam


def generate_payload():
    rnd = random.Random(20260401)
    OUT_DIR.mkdir(parents=True, exist_ok=True)
    payload = {
        "generated_at": datetime.now(timezone.utc).isoformat(),
        "workspace": str(NOTEBOOKLM_DIR),
        "source_dirs": [str(ROOT / "pdf"), str(ROOT / "dzi")],
        "source_datasets": [str(NVO_DATASET), str(DZI_DATASET)],
        "source_stats": source_stats(),
        "assumption": "Mocks are BEL-focused and modeled on the extracted local NVO BEL and DZI BEL structures.",
        "nvo_exams": [build_nvo_exam(i, rnd) for i in range(10)],
        "dzi_exams": [build_dzi_exam(i, rnd) for i in range(10)],
    }
    return payload


def validate_payload(payload):
    errors = []
    for exam in payload["nvo_exams"]:
        mismatches = validate_questions(exam["questions"], "nvo")
        if mismatches:
            errors.append((exam["title"], mismatches))
    for exam in payload["dzi_exams"]:
        mismatches = validate_questions(exam["questions"], "dzi")
        if mismatches:
            errors.append((exam["title"], mismatches))
    if errors:
        lines = ["Generated payload contains textbook-invalid literature references:"]
        for title, mismatches in errors:
            details = ", ".join(f"Q{number}: {', '.join(titles)}" for number, titles in mismatches)
            lines.append(f"- {title}: {details}")
        raise ValueError("\n".join(lines))


def write_markdown(payload):
    lines = [
        "# Mock NVO and DZI BEL Exams",
        "",
        f"- Generated at: {payload['generated_at']}",
        f"- Workspace: {payload['workspace']}",
        f"- Assumption: {payload['assumption']}",
        "",
    ]
    for group_name, exams in [("NVO BEL", payload["nvo_exams"]), ("DZI BEL", payload["dzi_exams"])]:
        lines.append(f"## {group_name}")
        lines.append("")
        for exam in exams:
            lines.append(f"### {exam['title']}")
            lines.append("")
            if exam["exam_type"] == "nvo_bel":
                lines.append(f"- Контекст: {exam['context_title']}")
                lines.append(f"- Текст: {exam['context_text']}")
                lines.append(f"- Инфографика: {json.dumps(exam['infographic'], ensure_ascii=False)}")
            else:
                lines.append(f"- Текст 1: {exam['text_1']}")
                lines.append(f"- Текст 2: {exam['text_2']}")
                lines.append(f"- Диаграма: {json.dumps(exam['diagram_summary'], ensure_ascii=False)}")
            lines.append("")
            for q in exam["questions"]:
                lines.append(f"#### {q['number']}. {q['question']}")
                if "options" in q:
                    for label, value in q["options"].items():
                        lines.append(f"- {label}: {value}")
                    lines.append(f"- Верен отговор: {q['correct_option']}")
                if "table_rows" in q:
                    lines.append(f"- Таблица: {json.dumps(q['table_rows'], ensure_ascii=False)}")
                if "pairs" in q:
                    lines.append(f"- Връзки: {json.dumps(q['pairs'], ensure_ascii=False)}")
                lines.append(f"- Насока за отговор: {json.dumps(q['answer_guide'], ensure_ascii=False)}")
                lines.append("")
    MD_OUT.write_text("\n".join(lines), encoding="utf-8")


